import { Logger } from "./libs/LoggerES6.js";
import MagicPortal from "./libs/MagicPortalES6.js";
import { getConfig } from './configES6.js';

const config = await getConfig();
const logger = new Logger(config.logging.WorkerPool);

function consoleDotLog(...parameters) {
  logger.consoleDotLog('[WorkerPool]', ...parameters);
}

function consoleDotError(...parameters) {
  logger.consoleDotError('[WorkerPool]', ...parameters);
}

consoleDotLog('Loading workerPool.');

// Helper to wrap Node Worker to look like Browser Worker
class NodeWorkerWrapper {
  constructor(worker, workerPath) {
    this.worker = worker;
    this.workerPath = workerPath;
    this.listeners = new Map();
    
    consoleDotLog(`[NodeWorkerWrapper] Created wrapper for worker at: ${workerPath}`);
    
    this.worker.on('message', (message) => {
      const event = { data: message };
      if (this.onmessage) this.onmessage(event);
      const listeners = this.listeners.get('message') || [];
      listeners.forEach(fn => fn(event));
    });
    
    this.worker.on('error', (err) => {
      consoleDotError(`[NodeWorkerWrapper] Worker error from ${workerPath}:`, err);
      const listeners = this.listeners.get('error') || [];
      listeners.forEach(fn => fn(err));
    });
    
    this.worker.on('exit', (code) => {
      consoleDotLog(`[NodeWorkerWrapper] Worker from ${workerPath} exited with code ${code}`);
    });
  }

  postMessage(message) {
    this.worker.postMessage(message);
  }

  addEventListener(type, listener) {
    if (!this.listeners.has(type)) this.listeners.set(type, []);
    this.listeners.get(type).push(listener);
  }

  terminate() {
    consoleDotLog(`[NodeWorkerWrapper] Terminating worker from ${this.workerPath}`);
    return this.worker.terminate();
  }
}

class WorkerPool {
  constructor() {
    this.workers = new Map();
    this.workerCount = 0;
    this.isNode = typeof window === 'undefined';
    consoleDotLog(`WorkerPool initialized. Environment: ${this.isNode ? 'Node.js' : 'Browser'}`);
  }

  async getWorker(mountPath, useSW = false) {
    try {
      consoleDotLog(`[getWorker] Request for mountPath: "${mountPath}", useSW: ${useSW}`);
      
      if (!this.workers.has(mountPath)) {
        consoleDotLog(`[getWorker] No existing worker for ${mountPath}, creating new one...`);
        let workerInstance;
        let workerSourcePath = null;

        if (this.isNode) {
            // --- NODE.JS: Dynamic Import to avoid Vite bundling errors ---
            consoleDotLog('[getWorker] ENVIRONMENT: Node.js detected');
            
            const { Worker } = await import('worker_threads');
            const { fileURLToPath } = await import('url');
            const { dirname, join, resolve } = await import('path');
            const { existsSync } = await import('fs');
            
            // Get current file paths
            const __filename = fileURLToPath(import.meta.url);
            const __dirname = dirname(__filename);
            
            consoleDotLog(`[getWorker] Node.js - __filename: ${__filename}`);
            consoleDotLog(`[getWorker] Node.js - __dirname: ${__dirname}`);
            
            // Try multiple possible paths for the worker
            const possiblePaths = [
              join(__dirname, 'workers', 'gitWorker.js'),
              join(__dirname, '../workers/gitWorker.js'),
              join(process.cwd(), 'workers', 'gitWorker.js'),
              join(process.cwd(), 'src/workers', 'gitWorker.js'),
              resolve('./workers/gitWorker.js'),
              resolve('./src/workers/gitWorker.js')
            ];
            
            let workerPath = null;
            for (const testPath of possiblePaths) {
              if (existsSync(testPath)) {
                workerPath = testPath;
                consoleDotLog(`[getWorker] ✓ Found worker at: ${workerPath}`);
                break;
              } else {
                consoleDotLog(`[getWorker] ✗ Worker not found at: ${testPath}`);
              }
            }
            
            if (!workerPath) {
              throw new Error(`Could not find gitWorker.js in any of the searched locations: ${possiblePaths.join(', ')}`);
            }
            
            workerSourcePath = workerPath;
            consoleDotLog(`[getWorker] Creating Node Worker from: ${workerPath}`);
            
            const rawWorker = new Worker(workerPath);
            consoleDotLog(`[getWorker] Node Worker instance created successfully from ${workerPath}`);
            
            workerInstance = new NodeWorkerWrapper(rawWorker, workerPath);
        } else {
            // --- BROWSER: Standard Worker ---
            consoleDotLog('[getWorker] ENVIRONMENT: Browser detected');
            
            // Get the current script's URL
            const currentScriptUrl = import.meta.url;
            consoleDotLog(`[getWorker] Browser - Current script URL: ${currentScriptUrl}`);
            
            // Try to construct worker URL
            const workerUrl = new URL('./workers/gitWorker.js', import.meta.url);
            consoleDotLog(`[getWorker] Browser - Constructed worker URL: ${workerUrl.href}`);
            
            // Log the full resolution path
            consoleDotLog(`[getWorker] Browser - Worker will load from absolute URL: ${workerUrl.href}`);
            consoleDotLog(`[getWorker] Browser - URL components - origin: ${workerUrl.origin}, pathname: ${workerUrl.pathname}`);
            
            workerSourcePath = workerUrl.href;
            workerInstance = new Worker(workerUrl, { type: 'module' });
            
            consoleDotLog(`[getWorker] Browser Worker instance created from ${workerUrl.href}`);
            
            // Add browser-specific error logging
            workerInstance.onerror = (error) => {
              consoleDotError(`[getWorker] Browser Worker error event from ${workerUrl.href}:`, error);
            };
        }
  
        consoleDotLog(`[getWorker] Creating MagicPortal for worker from: ${workerSourcePath}`);
        const portal = new MagicPortal(workerInstance);
        
        consoleDotLog(`[getWorker] Waiting for worker thread from ${workerSourcePath}...`);
        const thread = await Promise.race([
          portal.get("workerThread"),
          new Promise((_, reject) => 
            setTimeout(() => reject(new Error(`Worker thread timeout after 10s from ${workerSourcePath}`)), 10000)
          )
        ]);
        
        consoleDotLog(`[getWorker] Worker thread obtained from ${workerSourcePath}, waiting for readiness...`);
        await thread.ready();
        consoleDotLog(`[getWorker] Worker from ${workerSourcePath} is ready`);
  
        this.workers.set(mountPath, {
          worker: workerInstance,
          portal,
          thread,
          users: 0,
          workerSource: workerSourcePath,
          createdAt: new Date().toISOString()
        });
        
        this.workerCount++;
        consoleDotLog(`[getWorker] Worker for ${mountPath} initialized successfully from ${workerSourcePath}. Total workers: ${this.workerCount}`);
      } else {
        const existingEntry = this.workers.get(mountPath);
        consoleDotLog(`[getWorker] Reusing existing worker for ${mountPath} (originally from ${existingEntry.workerSource}, created at ${existingEntry.createdAt})`);
      }
  
      const entry = this.workers.get(mountPath);
      entry.users++;
      consoleDotLog(`[getWorker] Worker for ${mountPath} now has ${entry.users} active user(s)`);
      
      return entry;
    } catch (error) {
      consoleDotError(`[getWorker] Failed to get worker for ${mountPath}:`, error);
      consoleDotError(`[getWorker] Error stack: ${error.stack}`);
      throw error;
    }
  }

  async releaseWorker(mountPath) {
    consoleDotLog(`[releaseWorker] Releasing worker for ${mountPath}`);
    
    if (this.workers.has(mountPath)) {
      const entry = this.workers.get(mountPath);
      entry.users--;
      consoleDotLog(`[releaseWorker] Worker for ${mountPath} users left: ${entry.users} (was loaded from ${entry.workerSource})`);
      
      if (entry.users <= 0) {
        consoleDotLog(`[releaseWorker] No more users for ${mountPath}, terminating worker (was from ${entry.workerSource})`);
        await entry.worker.terminate();
        this.workers.delete(mountPath);
        this.workerCount--;
        consoleDotLog(`[releaseWorker] Worker terminated for ${mountPath}. Total workers left: ${this.workerCount}`);
      } else {
        consoleDotLog(`[releaseWorker] Keeping worker for ${mountPath} active (${entry.users} users remaining)`);
      }
    } else {
      consoleDotLog(`[releaseWorker] No worker found for ${mountPath} to release`);
    }
  }
}

export const workerPool = new WorkerPool();

// Log the final state
consoleDotLog(`WorkerPool module loaded successfully. Environment: ${workerPool.isNode ? 'Node.js' : 'Browser'}`);